+// ----------------------------------------------------
+// スプレッドシートから YOYAKL への直接データ出力（同期）
+// ----------------------------------------------------
+
+function parseReservationCell(text) {
+  if (!text) return null;
+  text = text.trim();
+  if (text === '') return null;
+
+  // 改行で分割
+  const lines = text.split('\n').map(line => line.trim()).filter(line => line !== '');
+  if (lines.length === 0) return null;
+
+  let timeStr = '';
+  let customerLine = '';
+  let memoLines = [];
+
+  // 1行目が時間帯であるかチェック
+  const timeRegex = /(\d{1,2})[：:]?(\d{2})[\s\-〜~ー]+(\d{1,2})[：:]?(\d{2})/;
+  const timeMatch = lines[0].match(timeRegex);
+
+  if (timeMatch) {
+    timeStr = lines[0];
+    if (lines.length > 1) {
+      customerLine = lines[1];
+      memoLines = lines.slice(2);
+    }
+  } else {
+    // 1行目に時間帯がない場合、テキスト全体から時間帯を探す
+    // 例: "1200-1300鈴木" のような改行なしパターン
+    const inlineMatch = text.match(timeRegex);
+    if (inlineMatch) {
+      const matchedTime = inlineMatch[0];
+      timeStr = matchedTime;
+      customerLine = text.replace(matchedTime, '').trim();
+    } else {
+      // 時間帯が見つからないセルは予約ではない
+      return null;
+    }
+  }
+
+  // 時間帯のパース
+  const parsedTime = timeStr.match(timeRegex);
+  if (!parsedTime) return null;
+
+  const startH = parsedTime[1].padStart(2, '0');
+  const startM = parsedTime[2];
+  const endH = parsedTime[3].padStart(2, '0');
+  const endM = parsedTime[4];
+  const startTime = `${startH}:${startM}`;
+  const endTime = `${endH}:${endM}`;
+
+  // 顧客名、電話番号、指名区分のパース
+  let customerName = 'ゲスト';
+  let phoneSuffix = '';
+  let designation = 'free';
+
+  if (customerLine) {
+    // 電話番号下4桁の抽出
+    const phoneMatch = customerLine.match(/\d{4}/);
+    if (phoneMatch) {
+      phoneSuffix = phoneMatch[0];
+      customerLine = customerLine.replace(phoneSuffix, '');
+    }
+
+    // 指名区分の抽出
+    const cleanLower = customerLine.toLowerCase();
+    if (cleanLower.indexOf('b') !== -1 || cleanLower.indexOf('本') !== -1) {
+      designation = 'confirmed';
+      customerLine = customerLine.replace(/[bB本]/g, '').replace(/指名/g, '');
+    } else if (cleanLower.indexOf('s') !== -1 || cleanLower.indexOf('新') !== -1 || cleanLower.indexOf('初回') !== -1) {
+      designation = 'first_nomination';
+      customerLine = customerLine.replace(/[sS新]/g, '').replace(/初回(指名)?/g, '');
+    } else if (cleanLower.indexOf('指') !== -1) {
+      designation = 'nomination';
+      customerLine = customerLine.replace(/指(名)?/g, '');
+    } else if (cleanLower.indexOf('姫') !== -1) {
+      designation = 'princess';
+      customerLine = customerLine.replace(/姫(予約)?/g, '');
+    }
+
+    // 顧客名のクレンジング (様、括弧、余分なスペースの除去)
+    customerName = customerLine
+      .replace(/[（\(\)）]/g, '')
+      .replace(/様$/, '')
+      .trim();
+
+    if (!customerName) {
+      customerName = 'ゲスト';
+    }
+  }
+
+  const duration = calculateDuration(startTime, endTime);
+
+  return {
+    startTime: startTime,
+    endTime: endTime,
+    customerName: customerName,
+    phoneSuffix: phoneSuffix,
+    designation: designation,
+    duration: duration,
+    notes: memoLines.join('\n') || text
+  };
+}
+
+function exportDataToYoyakl() {
+  const ss = SpreadsheetApp.getActiveSpreadsheet();
+  const sheet = ss.getActiveSheet();
+  const sheetName = sheet.getName();
+
+  // 現在のシート名に一致する店舗設定を検索
+  let shopKey = null;
+  for (const key in SHOP_CONFIG) {
+    if (SHOP_CONFIG[key].sheetName === sheetName) {
+      shopKey = key;
+      break;
+    }
+  }
+
+  if (!shopKey) {
+    SpreadsheetApp.getUi().alert('❌ 現在アクティブなシート「' + sheetName + '」は店舗設定に登録されていません。');
+    return;
+  }
+
+  const config = SHOP_CONFIG[shopKey];
+  const ui = SpreadsheetApp.getUi();
+  const response = ui.alert(
+    '🔄 同期確認',
+    `店舗「${config.name}」のデータを YOYAKL に直接出力（同期）します。\nよろしいですか？`,
+    ui.ButtonSet.YES_NO
+  );
+
+  if (response !== ui.Button.YES) {
+    return;
+  }
+
+  // シートの全列を走査
+  const maxCols = sheet.getLastColumn();
+  const maxRows = sheet.getLastRow();
+  if (maxCols === 0 || maxRows === 0) {
+    ui.alert('❌ シートにデータがありません。');
+    return;
+  }
+
+  const shifts = [];
+  const reservations = [];
+  const dateSet = new Set();
+
+  for (let col = 1; col <= maxCols; col++) {
+    // 1行目の日付を確認
+    const dateVal = sheet.getRange(1, col).getValue();
+    if (!dateVal) continue;
+
+    let dateStr = '';
+    if (dateVal instanceof Date) {
+      dateStr = Utilities.formatDate(dateVal, 'Asia/Tokyo', 'yyyy-MM-dd');
+    } else {
+      const dateMatch = dateVal.toString().match(/(\d{4})[/\-年](\d{1,2})[/\-月](\d{1,2})/);
+      if (dateMatch) {
+        const y = dateMatch[1];
+        const m = dateMatch[2].padStart(2, '0');
+        const d = dateMatch[3].padStart(2, '0');
+        dateStr = `${y}-${m}-${d}`;
+      } else {
+        const shortMatch = dateVal.toString().match(/(\d{1,2})[/\-月](\d{1,2})/);
+        if (shortMatch) {
+          const m = shortMatch[1].padStart(2, '0');
+          const d = shortMatch[2].padStart(2, '0');
+          dateStr = `2026-${m}-${d}`;
+        }
+      }
+    }
+
+    if (!dateStr) continue;
+
+    // 4行目のスタッフ名
+    const staffVal = sheet.getRange(4, col).getValue();
+    if (!staffVal) continue;
+
+    const staffName = staffVal.toString().trim().replace(/\d+(精算)?$/, '');
+
+    // 5行目のルーム名
+    const roomVal = sheet.getRange(5, col).getValue();
+    const roomName = roomVal ? roomVal.toString().trim() : '';
+
+    // 6行目の出勤時間
+    const timeVal = sheet.getRange(6, col).getValue();
+    if (!timeVal) continue;
+
+    const timeMatch = timeVal.toString().replace(/[^0-9\-]/g, '').match(/^(\d{2})(\d{2})[-〜](\d{2})(\d{2})$/);
+    if (!timeMatch) continue;
+
+    const startH = timeMatch[1];
+    const startM = timeMatch[2];
+    const endH = timeMatch[3];
+    const endM = timeMatch[4];
+    const startTime = `${startH}:${startM}`;
+    const endTime = `${endH}:${endM}`;
+
+    // 出勤枠の追加
+    shifts.push({
+      date: dateStr,
+      therapist_name: staffName,
+      room_name: roomName,
+      start_time: startTime,
+      end_time: endTime
+    });
+
+    dateSet.add(dateStr);
+
+    // 7行目以降の予約情報をスキャン
+    for (let row = 7; row <= maxRows; row++) {
+      const cellText = sheet.getRange(row, col).getValue();
+      const parsedRes = parseReservationCell(cellText.toString());
+      if (parsedRes) {
+        reservations.push({
+          date: dateStr,
+          therapist_name: staffName,
+          customer_name: parsedRes.customerName,
+          phone_suffix: parsedRes.phoneSuffix || undefined,
+          start_time: parsedRes.startTime,
+          end_time: parsedRes.endTime,
+          duration: parsedRes.duration,
+          designation_type: parsedRes.designation,
+          notes: parsedRes.notes
+        });
+      }
+    }
+  }
+
+  if (shifts.length === 0) {
+    ui.alert('⚠️ 有効なシフト情報が見つかりませんでした。');
+    return;
+  }
+
+  // YOYAKL API への送信
+  const token = 'yoyakl_sync_token_2026';
+  // TODO: 本番稼働時は 'https://your-yoyakl-domain.com' に置き換えてください
+  const baseUrl = 'http://localhost:3000';
+  const url = `${baseUrl}/api/public/sync-from-spreadsheet`;
+
+  const payload = {
+    token: token,
+    shopId: config.supabaseShopId,
+    dates: Array.from(dateSet),
+    shifts: shifts,
+    reservations: reservations
+  };
+
+  try {
+    const response = UrlFetchApp.fetch(url, {
+      method: 'post',
+      contentType: 'application/json',
+      payload: JSON.stringify(payload),
+      muteHttpExceptions: true
+    });
+
+    const code = response.getResponseCode();
+    const text = response.getContentText();
+    const result = JSON.parse(text);
+
+    if (code === 200 && result.success) {
+      ui.alert('✅ 同期完了', `YOYAKL への同期が成功しました！\n出勤: ${result.shifts_count} 件\n予約: ${result.reservations_count} 件`, ui.ButtonSet.OK);
+    } else {
+      ui.alert('❌ 同期失敗', `エラーが発生しました:\n${result.error || text}`, ui.ButtonSet.OK);
+    }
+  } catch (err) {
+    ui.alert('❌ 通信エラー', `サーバーとの通信に失敗しました:\n${String(err)}`, ui.ButtonSet.OK);
+  }
+}
+
 

